export function deeplyNested(input: number): number {
  if (input > 0) {
    for (let index = 0; index < input; index += 1) {
      while (index < input * 2) {
        try {
          if (index % 2 === 0) {
            switch (input) {
              case 1:
                return index;
              default:
                return input;
            }
          }
        } catch (error) {
          throw error;
        }
        break;
      }
    }
  }
  return 0;
}
